(function(w){"use strict";const ID="time-diff";function mins(v){const m=/^(\d{1,2}):(\d{2})$/.exec(v||"");if(!m)return null;const h=Number(m[1]),n=Number(m[2]);return h>=0&&h<24&&n>=0&&n<60?h*60+n:null}function compute(x){const a=mins(x.start),b=mins(x.end);if(a===null||b===null)return{error:"시간을 HH:MM 형식으로 입력해 주세요."};let d=b-a;if(x.nextDay===true||x.nextDay==='true')d+=1440;if(d<0)return{error:"종료 시간이 더 이르면 '다음 날 종료'를 선택해 주세요."};return{minutes:d,hours:Math.floor(d/60),remainingMinutes:d%60}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>시작 시간</label><input class="hm-calc-input" type="time" value="09:00"></div><div class="hm-calc-field"><label>종료 시간</label><input class="hm-calc-input" type="time" value="18:00"></div></div><label class="hm-calc-check"><input type="checkbox"> 종료 시간은 다음 날</label><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">시간 차이 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const times=root.querySelectorAll('input[type="time"]'),check=root.querySelector('input[type="checkbox"]'),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({start:times[0].value,end:times[1].value,nextDay:check.checked});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("시간 차이",`${r.hours}시간 ${r.remainingMinutes}분`,`총 ${api.formatNumber(r.minutes,0)}분`));});}
w.HM_CALC.register(ID,{compute,render});})(window);
